CREATE TABLE IF NOT EXISTS "sales_return" ("id" text PRIMARY KEY,"returnNo" text NOT NULL,"saleId" text NOT NULL,"receiptNo" text NOT NULL,"amount" numeric(12,2) NOT NULL,"refundMethod" text NOT NULL,"reason" text NOT NULL,"status" text NOT NULL DEFAULT 'completed',"userId" text NOT NULL,"orgId" text NOT NULL,"createdAt" timestamp NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS "sales_return_org_idx" ON "sales_return"("orgId");
CREATE TABLE IF NOT EXISTS "sales_return_item" ("id" text PRIMARY KEY,"returnId" text NOT NULL REFERENCES "sales_return"("id") ON DELETE CASCADE,"productId" text NOT NULL,"productName" text NOT NULL,"quantity" integer NOT NULL,"unitPrice" numeric(12,2) NOT NULL,"total" numeric(12,2) NOT NULL,"disposition" text NOT NULL DEFAULT 'restock',"orgId" text NOT NULL);
CREATE TABLE IF NOT EXISTS "inventory_loss" ("id" text PRIMARY KEY,"lossNo" text NOT NULL,"productId" text NOT NULL,"productName" text NOT NULL,"quantity" integer NOT NULL,"type" text NOT NULL,"unitCost" numeric(12,2) NOT NULL,"totalCost" numeric(12,2) NOT NULL,"reason" text NOT NULL,"userId" text NOT NULL,"orgId" text NOT NULL,"createdAt" timestamp NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS "inventory_loss_org_idx" ON "inventory_loss"("orgId");
CREATE TABLE IF NOT EXISTS "pos_session" ("id" text PRIMARY KEY,"sessionNo" text NOT NULL,"status" text NOT NULL DEFAULT 'open',"openingCash" numeric(12,2) NOT NULL DEFAULT 0,"expectedCash" numeric(12,2),"closingCash" numeric(12,2),"variance" numeric(12,2),"notes" text,"openedBy" text NOT NULL,"closedBy" text,"orgId" text NOT NULL,"openedAt" timestamp NOT NULL DEFAULT now(),"closedAt" timestamp);
CREATE INDEX IF NOT EXISTS "pos_session_org_idx" ON "pos_session"("orgId");
CREATE TABLE IF NOT EXISTS "cash_movement" ("id" text PRIMARY KEY,"sessionId" text NOT NULL REFERENCES "pos_session"("id") ON DELETE CASCADE,"type" text NOT NULL,"amount" numeric(12,2) NOT NULL,"reason" text NOT NULL,"userId" text NOT NULL,"orgId" text NOT NULL,"createdAt" timestamp NOT NULL DEFAULT now());
